CREATE TRIGGER [Global].[Site_History]ON [Global].[Site]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.SiteId IS NOT NULL AND d.SiteId IS NULL THEN 'I' 		WHEN i.SiteId IS NOT NULL AND d.SiteId IS NOT NULL THEN 'U' 		WHEN i.SiteId IS NULL AND d.SiteId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.SiteId = d.SiteId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Global_Site([SiteId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [SiteId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Global_Site([SiteId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [SiteId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND